// TODO: scripts/validate-agent-output.js の validateAgentOutput("acquisition", output) 相当の検証をここで行う
const output = { x_ads: [], lp: {}, next_test_recommendation: {} };

// prompts/acquisition.md のOutput JSON schemaから、Sheets書き込み前の要約ビューを組み立てる
const result = {
  x_ads_candidates: output.x_ads,
  lp_outline: output.lp,
  test_variable: output.next_test_recommendation.variable || (output.lp && output.lp.test_variable) || "",
  hypothesis: (output.lp && output.lp.hypothesis) || (output.x_ads[0] && output.x_ads[0].hypothesis) || "",
};

return [{ json: result }];
